 1	import React, { FC, useState } from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { kubevirtConsole } from '@kubevirt-utils/utils/utils';
 6	import { useActiveNamespace } from '@openshift-console/dynamic-plugin-sdk';
 7	import { ActionGroup, Alert, AlertVariant, Button, ButtonVariant } from '@patternfly/react-core';
 8	
 9	import { createNetworkCheckup } from '../../utils/utils';
10	
11	type CheckupsNetworkFormActionsProps = {
12	  desiredLatency: string;
13	  isNodesChecked: boolean;
14	  name: string;
15	  nodeSource: string;
16	  nodeTarget: string;
17	  sampleDuration: string;
18	  selectedNAD: string;
19	};
20	
21	const CheckupsNetworkFormActions: FC<CheckupsNetworkFormActionsProps> = ({
22	  desiredLatency,
23	  isNodesChecked,
24	  name,
25	  nodeSource,
26	  nodeTarget,
27	  sampleDuration,
28	  selectedNAD,
29	}) => {
30	  const { t } = useKubevirtTranslation();
31	  const navigate = useNavigate();
32	  const [namespace] = useActiveNamespace();
33	  const [error, setError] = useState<string>(null);
34	  const shouldDisableNodes = isNodesChecked ? nodeSource && nodeTarget : true;
35	  const isSubmitDisabled = !name || !selectedNAD || !shouldDisableNodes;
36	
37	  return (
38	    <>
39	      <ActionGroup>
40	        <Button
41	          onClick={async () => {
42	            setError(null);
43	            try {
44	              await createNetworkCheckup({
45	                desiredLatency,
46	                name,
47	                namespace,
48	                nodeSource,
49	                nodeTarget,
50	                sampleDuration,
51	                selectedNAD,
52	              });
53	              navigate(`/k8s/ns/${namespace}/checkups`);
54	            } catch (e) {
55	              kubevirtConsole.log(e);
56	              setError(e?.message);
57	            }
58	          }}
59	          isDisabled={isSubmitDisabled}
60	          variant={ButtonVariant.primary}
61	        >
62	          {t('Run')}
63	        </Button>
64	        <Button onClick={() => navigate(-1)} variant={ButtonVariant.secondary}>
65	          {t('Cancel')}
66	        </Button>
67	      </ActionGroup>
68	      {error && (
69	        <Alert title={t('Failed to create resource')} variant={AlertVariant.danger}>
70	          {error}
71	        </Alert>
72	      )}
73	    </>
74	  );
75	};
76	
77	export default CheckupsNetworkFormActions;

